UPDATE public.designer_profiles SET
  design_background = 'I am Shubham Malpani, co-founder at Cyanique and a long-time design enthusiast with a deep love for sculptural furniture. My background sits at the intersection of materials, manufacturing and form — I spend most of my time thinking about how an object is made and how that process shapes the final piece. I am drawn to organic, flowing silhouettes that feel handcrafted yet engineered, and I enjoy collaborating with creators to translate their concepts into physical pieces that hold up to real life.',
  furniture_interests = 'I love designing tables and organically shaped chairs that feel sculptural in a room — pieces with soft curves, generous proportions and a strong material story. My focus is on dining and accent tables, lounge seating, and statement consoles where form and function blend into a single, considered object.',
  updated_at = now()
WHERE id = '2d21ebbc-84b9-4fd0-96c0-633392e084be';

UPDATE public.designer_profiles SET
  design_background = 'I am Tejal Agawane, an architect and co-founder at Cyanique. My practice has always moved between architecture and product design — designing spaces first, and then the objects that bring those spaces to life. I approach furniture the same way I approach a building: with a strong point of view on proportion, light, and how a piece sits in its environment. I am especially interested in contemporary Indian design that balances global modernism with our own material and craft traditions.',
  furniture_interests = 'I focus on furniture and home decor that anchor a space — sculptural seating, accent chairs, consoles, side tables and lighting objects. I love working on pieces that feel architectural in scale and presence, where every angle and finish has been considered. Sustainable, long-life materials and a calm, editorial aesthetic guide most of my work.',
  portfolio_url = 'https://www.cyanique.com',
  updated_at = now()
WHERE id = '6f4688ef-d568-42da-8a9b-d76b4db263b1';

UPDATE public.designer_profiles SET
  design_background = 'I am Nikunj Jakhotia, a design enthusiast with a passion for translating ideas into objects you can actually live with. My approach is grounded in functionality first — I like furniture that earns its place in a home through everyday usability — and then layered with quiet, modern detailing. I am especially interested in how AI-assisted tools can help non-designers like me explore form quickly, and I enjoy iterating until a piece feels both honest and refined.',
  furniture_interests = 'I love designing tables and chairs — the two pieces that quietly define how a room feels. My focus is on dining tables, work tables and contemporary chairs with clean silhouettes, warm finishes and a balance between minimal and inviting. I gravitate towards pieces that work equally well in compact urban homes and larger, more expressive interiors.',
  updated_at = now()
WHERE id = 'a1426e2b-e409-4b23-bce5-b1ee966bbff2';

UPDATE public.designer_profiles SET
  design_background = 'I am Anuj Jakhotia, a design enthusiast exploring furniture as a way to bring more character into modern spaces. I do not come from a formal design background, but I have always been drawn to the craft of objects — how a chair takes weight, how a table holds a moment, how a small detail changes the entire feel of a piece. I enjoy using AI design tools to explore forms I would not have arrived at on my own, then refining them into pieces that feel intentional and well-made.',
  furniture_interests = 'I focus on seatings and tables — accent chairs, lounge seating, side tables and coffee tables. I am drawn to sculptural silhouettes with soft, organic curves and rich, warm finishes. My work leans into contemporary statement pieces that act as quiet focal points in a living room or studio space.',
  updated_at = now()
WHERE id = '51eedcca-9703-45a3-9906-1929fa630fde';

UPDATE public.designer_profiles SET
  design_background = 'I am the founder of Sach Creations, a small studio that started with handcrafted bags and has grown into a broader love for objects and furniture. My background is rooted in craft and material — understanding how textures, finishes and small handmade details elevate everyday products. I bring that same sensibility into furniture design, focusing on pieces that feel tactile, considered and made for everyday use rather than just display.',
  furniture_interests = 'I focus on seatings — accent chairs, stools, benches and lounge pieces — designed to feel warm, inviting and a little sculptural. I love combining contemporary forms with material-rich finishes that age well, and I am especially interested in seating that brings personality into living rooms, studios and intimate gathering spaces.',
  updated_at = now()
WHERE id = '8ae59a45-8841-4053-98de-f47226feaacf';

UPDATE public.designer_profiles SET
  design_background = 'I am Farhan Sayyed, a design enthusiast exploring furniture and product design as a way to shape the spaces I live and work in. My approach is curious and experimental — I like starting from a feeling or a use-case rather than a strict style, and letting the form emerge through iteration. AI-assisted design tools have made it easier for me to move from rough ideas to refined concepts, and I enjoy pushing for pieces that feel both modern and personal.',
  furniture_interests = 'I am interested in contemporary furniture across seating, tables and accent pieces — chairs, stools, side tables and consoles with clean lines, balanced proportions and a strong material presence. I gravitate towards minimal, modern silhouettes warmed up with rich finishes, and I love pieces that work as quiet statements in everyday spaces.',
  updated_at = now()
WHERE id = '507a4329-7f73-4d2b-9f55-815de8d14086';